// src/components/ui/LiveIndicator.tsx
import { useSelector } from 'react-redux';
import { RootState } from '@/store';
import { Tooltip } from '@/components/ui/tooltip';

export function LiveIndicator() {
  const { latency, isConnected } = useSelector((s: RootState) => s.ws);
  const color = latency < 200 ? 'bg-emerald-400' :
                latency < 500 ? 'bg-amber-400' : 'bg-rose-400';

  return (
    <Tooltip content={`WS ${isConnected ? 'online' : 'offline'} • ${latency} ms`}>
      <span
        role="status"
        aria-live="polite"
        className={`inline-block h-3 w-3 rounded-full ${color} animate-pulse`}
      />
    </Tooltip>
  );
}
```

